import { NextResponse } from "next/server";import { getSupabaseAdmin } from "@/lib/supabaseAdmin";
export async function POST(req){const b=await req.json();const supabase=getSupabaseAdmin();const v=b.vendor||{};if(!supabase)return NextResponse.json({ok:false,mode:"placeholder",message:"Add Supabase keys to save vendor applications.",vendor:v});const {error}=await supabase.from("vendors").insert({business_name:v.name||"",category:v.category||"",location:v.location||"",price_range:v.price||"",email:v.email||"",status:"pending",verified:false});if(error)return NextResponse.json({ok:false,message:error.message},{status:500});return NextResponse.json({ok:true,message:"Vendor application saved."});}